import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.HttpRequest
import akka.http.scaladsl.model.Uri
import akka.stream.ActorMaterializer
import scala.concurrent.Future

object WebhookProxy extends App {

  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: ActorMaterializer = ActorMaterializer()

  val route =
    path("fetch") {
      post {
        entity(as[String]) { userUrl =>
          val request = HttpRequest(uri = Uri(userUrl))
          val responseFuture: Future[HttpResponse] = Http().singleRequest(request)
          complete(responseFuture.map(_.entity))
        }
      }
    }

  Http().bindAndHandle(route, interface = "0.0.0.0", port = 8080)
}